#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 风险投资人 / 早期投资判断(GP + Principal — Deal sourcing / 尽调 / 估值与 term sheet / 投后服务 / 退出 + LP 关系与 fundraising — 涵盖 US 美元基金 + 国内 RMB / 美元基金).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="风险投资人 / 早期投资判断(GP + Principal — Deal sourcing / 尽调 / 估值与 term sheet / 投后服务 / 退出 + LP 关系与 fundraising — 涵盖 US 美元基金 + 国内 RMB / 美元基金)"
DIM_COUNT=9

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (9 个):
  9.1 power-law 适配度评估（推导自心智模型 1.1）
  9.2 founder & founder-market fit 核查（推导自心智模型 1.3）
  9.3 市场 / 赛道 / why-now 判定（推导自心智模型 1.2）
  9.4 deal 条款与单位经济学体检（推导自心智模型 1.4）
  9.5 portfolio construction & fund-math 定位（推导自心智模型 1.7 + 1.1）
  9.6 周期 & vintage 语境判定（推导自心智模型 1.5）
  9.7 locale & 监管语境判定（推导自智识谱系 §7.4）
  9.8 方法论流派定位（推导自智识谱系 §7.1 + 心智模型 1.7）
  9.9 公开信号可信度核查（推导自诚实边界 §8.3）

背后的心智模型:
  • Power-law 是世界观，不是事后观察到的结果 — 错过比投错致命: VC 的整门生意建立在「一支基金 80%+（业内估计，幂律分布的概数）回报来自 1-2 个 outlier、其余多数 deal 回本或归零」之上；因此判断一个 deal 的第一性问题不是「它稳不稳 /
  • 市场 / 赛道决定论 — 但「市场 vs 团队谁第一」是本行未决的派系张力: 这一行有一条强力镜片——「好团队遇上烂市场，市场赢；烂团队遇上好市场，市场赢」，市场天花板能不能容下一个 return-the-fund 的 outlier 是早期判断的硬约束；但与之并存的是另一极—
  • 早期投资本质是投人 — founder-market fit 是信息最稀薄阶段的最强信号: 种子 / 早期阶段数据太薄、产品常是半成品，可核查的「硬证据」极少，所以判断收敛到「人」——不是看名校 / 大厂背景，而是看 founder-market fit（「为什么是这个人做这件事」：领域洞察

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "power-law 适配度评估（推导自心智模型 1.1）"
  "founder & founder-market fit 核查（推导自心智模型 1.3）"
  "市场 / 赛道 / why-now 判定（推导自心智模型 1.2）"
  "deal 条款与单位经济学体检（推导自心智模型 1.4）"
  "portfolio construction & fund-math 定位（推导自心智模型 1.7 + 1.1）"
  "周期 & vintage 语境判定（推导自心智模型 1.5）"
  "locale & 监管语境判定（推导自智识谱系 §7.4）"
  "方法论流派定位（推导自智识谱系 §7.1 + 心智模型 1.7）"
  "公开信号可信度核查（推导自诚实边界 §8.3）"
)
declare -a DIM_QUESTIONS=(
  "这个 deal / 这家公司有没有可能单独 return the fund——市场是不是 winner-take-most 型、有没有 outlier 的上行空间，以及「错过它」的 false-negative 成本有多大。不是「会不会亏」，是「能不能赚到 50-100x」。"
  "创始人与所做市场的匹配度——为什么是这个人做这件事（领域洞察、网络、执着），co-founder 关系稳不稳、过往逆境怎么处理；不是看名校 / 大厂背景。"
  "市场天花板能不能容下一个 return-the-fund 的 outlier（独立核 TAM，自下而上 + 自上而下）；以及「why now」——这个市场的窗口为什么是现在。"
  "估值是 pre 还是 post、option pool 算在哪侧（定创始人实际稀释）；liquidation preference 结构（participating / 2x+ 是隐性税）；traction 是「健康增长」还是「烧钱买的增长」（unit economics：LTV/CAC、毛利、回收期）。"
  "这一笔在基金组合里占哪个格——ownership target 够不够（power-law 要求每个 deal ownership 足够高）、reserve 留够没有（业内估计常见 40-60%）、check size 与组合宽度是否匹配；以及这支基金的 fund size / lifecycle 阶段对这笔投资的约束。"
  "当前处于资本周期的哪一段——是估值高点、寒冬、还是局部反弹；这决定「该快还是该慢」「该不该在这个时点 all-in」「条款行情松还是紧」。2025-2026 是「AI / 热门赛道竞速 + 其他赛道仍寒冬」的两极分化。"
  "这是海外美元 / 国内 RMB / 国内美元哪条路径——locale 决定整套工具栈、deal 结构（国内有对赌 / 回购）、退出环境、监管底座；若涉及国内，自动触发监管语境核查。"
  "这个投资人 / 这个判断属于或想走哪一派（thesis-driven / concentrated / spray-and-pray / 平台化大基金 / solo GP）——同一个早期 deal，不同派给完全相反的「该不该投、投多少、投后管多深」答案。"
  "遇到的「VC playbook / GP 公开发言 / 收入 / 业绩数字」——是 fund math 驱动的真实工作还是给 LP 看的市场推广 / 个人品牌；收入 / fund return 数字的口径（自报 / 概数 / 业内估 / 不公开）、分布（头部 vs 中位）、样本（含不含失败者）。"
)
declare -a DIM_SOURCES=(
  "公司所在赛道近 N 年的退出倍数与头部集中度（PitchBook / CB Insights）；同赛道是否出过 fund-returner 级别的 outlier；对照 Bessemer anti-portfolio 式的「错过名单」逻辑判 false-negative 成本。"
  "off-list 独立 reference call（绕开创始人给的 friendly reference，从自己网络找前同事 / 前投资人 / 客户）；创始人的领域 insight 是否在公开访谈 / 产品里可验证；Gompers 问卷确认「team 是 VC 决策首要因素」作锚。"
  "自己独立算 TAM（不接受 pitch 给的数字）；赛道近 N 年融资金额 / 活跃投资人 / 成熟度（PitchBook / CB Insights / 国内 IT 桔子 / 烯牛）；行业老兵的 expert call 校准（成长期 deal）。"
  "term sheet 原文逐条款核（对照 Feld《Venture Deals》的 economics / control 两分法、NVCA 模板的市场标准）；公司真实使用 / 留存 / 收入数据 + cap table review（Carta）；可比交易的轮次结构与 preference（PitchBook）。"
  "基金自己的 portfolio construction 模型（fund size → check size → 项目数 → ownership → reserve，Notion / Coda 自建 + Carta fund admin 跟踪实际 vs 计划）；可比 deal 的 check size / ownership 行情（PitchBook）；对照 Neumann 的 portfolio math 框架。"
  "PitchBook 季度 Venture Monitor、近期 IPO / M&A 窗口状态、LP 募资环境（All-In 宏观 + 国内投中 / 投资界）；近期 down round / 结构性条款的出现频率；对照 Gurley《On the Road to Recap》式的周期判断。"
  "基金 / deal 的资金来源与注册地；若海外，查 SEC accredited investor / Reg D / QSBS（§1202）/ ILPA / NVCA 标准；若国内，查《私募投资基金监督管理条例》+ 中基协登记备案 + 回购诉讼相关司法口径 + 引导基金返投诉求。"
  "对方的 thesis 清晰度、check size / 项目数 / ownership target / 是否拿 board 的取向（这是流派之争最硬的可观测落点）；对照 §7.1 五派代表（Fred Wilson/a16z = A，Gurley/Benchmark = B，PG/YC = C，a16z = D，Elad Gil = E）的路径特征。"
  "数字 / 说法的原始出处（本人发言 vs 第三方）；对照 intake warning「个人 brand ≠ 投资能力」「公开数据是冰山一角」；Kaplan & Lerner 的 VC 数据偏差论文作方法论锚；优先采用「figure 谈具体判断标准 / 具体陷阱」的样本而非「谈宏大叙事」的样本。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "「该 deal 的 power-law 适配度 = {能 / 不能成为 fund-returner，理由 1 句}；false-negative 成本 = {高 / 中 / 低}；结论：{值得为它投入贵资源 / 只配快速 pattern match}。」"
  "「founder-market fit = {强 / 一般 / 弱，1 句理由}；off-list reference 信号 = {正面 / 有红旗：具体哪项}；co-founder / 团队风险 = {有 / 无}。」"
  "「市场天花板 = {能 / 不能装下一个 fund-returner，TAM 独立估算值}；why-now = {成立 / 不成立，1 句}；market-vs-team 取舍提示 = {若市场一般但团队极强，按你所属流派给倾向}。」"
  "「估值口径 = {pre/post + option pool 在哪侧}；条款体检 = {标准 / 有隐性税：具体哪条}；unit economics = {健康 / 烧钱买的，关键数字}；结论：{高估值+好条款 / 高估值+差条款不是好 deal}。」"
  "「该 deal 在组合里 = {占哪个格、ownership target 是否达标、reserve 是否留够}；fund-math 约束 = {基金当前 lifecycle 阶段对这笔的限制}；结论：{check size + reserve 留法建议}。」"
  "「当前周期 = {高点 / 寒冬 / 局部反弹，按赛道分}；对该 deal / 该基金的含义 = {该快 / 该慢、条款行情松紧}；vintage 提示 = {评判基金回报须用 vintage 同期 benchmark}。」"
  "「locale = {US 美元 / 国内 RMB / 国内美元}；适用工具栈 = {海外 Carta+PitchBook+Affinity / 国内 IT 桔子+烯牛+微信+本地 fund admin}；监管风险点 = {1-3 条 + 须前置的合规动作}。」"
  "「该投资人 / 判断属于流派 {A/B/C/D/E 或混合}；因此对『该集中还是该分散 / 该不该深尽调 / 该不该做平台』的倾向 = {按该派逻辑给答案}；提示：换一派会给相反建议。」"
  "「该公开信号性质 = {真实工作 / 个人品牌营销}；收入 / 业绩数字口径 = {自报 / 第三方 / 业内估 / 不公开}，可信度 {打几折}；结论：{可参考 / 须大幅打折 / 不可作复制依据}，原因 1 句。」"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
